300     private func errorEntries(
301         type: String,
302         credentials: CodexCredentials? = nil,
303         isActive: Bool = false,
304         preservedMetrics: [UsageMetric] = []
305     ) -> [VendorUsageEntry] {
306         guard let (account, source) = resolvePersistedAccount(credentials: credentials) else {
307             let accountId = credentials?.accountId.rawValue ?? "<unavailable>"
308             logger.log(.warning, "Codex identity_unresolved during \(type) for accountId=\(accountId) — no usage entry written")
309             return []
310         }
311         logger.log(.debug, "Codex resolved account=\(account) via \(source.rawValue) for \(type)")
312         return [errorEntry(account: account, type: type, isActive: isActive, preservedMetrics: preservedMetrics)]
313     }
